export interface CommandHandler {
  name: string;
  description: string;
  execute(orchestrator: any, args: string[]): Promise<void>;
}

export class CommandRegistry {
  private static commands = new Map<string, CommandHandler>();

  static register(handler: CommandHandler) {
    this.commands.set(handler.name, handler);
  }

  static get(name: string): CommandHandler | undefined {
    return this.commands.get(name);
  }

  static getAll(): CommandHandler[] {
    return Array.from(this.commands.values());
  }
}

import { CommandRegistry } from '../core/commands.js';
import { PlanHandler } from './plan.js';
import { DiffHandler } from './diff.js';
import { ReviewHandler, SecurityReviewHandler } from './review.js';
import { SimplifyHandler } from './simplify.js';

export function registerAllCommands() {
  CommandRegistry.register(new PlanHandler());
  CommandRegistry.register(new DiffHandler());
  CommandRegistry.register(new ReviewHandler());
  CommandRegistry.register(new SecurityReviewHandler());
  CommandRegistry.register(new SimplifyHandler());
}

import { CommandHandler } from '../core/commands.js';
import { Orchestrator, OrchestratorMode } from '../core/orchestrator.js';
import chalk from 'chalk';

export class PlanHandler implements CommandHandler {
  name = 'plan';
  description = 'Toggle Plan Mode (read-only strategizing)';

  async execute(orchestrator: Orchestrator) {
    const currentMode = orchestrator.getMode();
    const newMode = currentMode === OrchestratorMode.PLAN 
      ? OrchestratorMode.NORMAL 
      : OrchestratorMode.PLAN;

    orchestrator.setMode(newMode);
    console.log(chalk.blue.bold(`\n[Mode]: Switched to ${newMode}`));
    if (newMode === OrchestratorMode.PLAN) {
      console.log(chalk.blue('Tool calls that modify state will be intercepted. Edits will not be applied.'));
    }
  }
}

import { CommandHandler } from '../core/commands.js';
import { Orchestrator } from '../core/orchestrator.js';
import { tools } from '../core/tools.js';
import { showInteractiveDiff } from '../core/diff.js';
import chalk from 'chalk';

export class DiffHandler implements CommandHandler {
  name = 'diff';
  description = 'Show uncommitted changes';

  async execute(orchestrator: Orchestrator) {
    try {
      const cachedDiff = await tools.run_command({ command: 'git diff --cached' });
      const unstagedDiff = await tools.run_command({ command: 'git diff' });

      const fullDiff = (cachedDiff.stdout || '') + (unstagedDiff.stdout || '');

      if (!fullDiff.trim()) {
        console.log(chalk.yellow('No uncommitted changes.'));
        return;
      }

      await showInteractiveDiff(fullDiff);
    } catch (error: any) {
      console.error(chalk.red(`[Diff Error]: ${error.message}`));
    }
  }
}

import { CommandHandler } from '../core/commands.js';
import { Orchestrator } from '../core/orchestrator.js';

export class ReviewHandler implements CommandHandler {
  name = 'review';
  description = 'Perform a deep read-only code review of the workspace';

  async execute(orchestrator: Orchestrator) {
    await orchestrator.injectMessage({
      role: 'user',
      parts: [{ text: "Please perform a deep read-only code review of the current workspace. Focus on maintainability, performance, and idiomatic TypeScript patterns. Do not propose edits yet, just provide an analytical report." }]
    });
    await orchestrator.processTurn(0);
  }
}

export class SecurityReviewHandler implements CommandHandler {
  name = 'security-review';
  description = 'Perform a focused security review of the workspace';

  async execute(orchestrator: Orchestrator) {
    await orchestrator.injectMessage({
      role: 'user',
      parts: [{ text: "Please perform a focused security review of the current workspace. Identify potential vulnerabilities like shell injection, exposed credentials, or insecure configurations. Do not propose edits yet, just provide an analytical report." }]
    });
    await orchestrator.processTurn(0);
  }
}

import { CommandHandler } from '../core/commands.js';
import { Orchestrator } from '../core/orchestrator.js';

export class SimplifyHandler implements CommandHandler {
  name = 'simplify';
  description = 'Analyze and simplify complex code areas in recently edited files';

  async execute(orchestrator: Orchestrator) {
    await orchestrator.injectMessage({
      role: 'user',
      parts: [{ text: "Analyze the most recently edited files in the workspace. Identify areas with high complexity or 'code smells'. Propose a simplified, more readable refactor for one of these areas. After proposing the edits, run the project's tests (e.g., 'npm test' or equivalent) to verify that behavior is preserved." }]
    });
    await orchestrator.processTurn(0);
  }
}
